using System.IO;
using UnityEditor;
using UnityEditor.SceneManagement;
using UnityEngine;
using UnityEngine.SceneManagement;

// Clean BootPlayMode implementation
[InitializeOnLoad]
internal static class BootPlayMode
{
    private const string PrefOriginalScene = "BootPlayMode_OriginalScene";
    private const string PrefBootPath = "BootPlayMode_BootPath";
    private const string BootSceneName = "_Boot";
    private static string pendingOriginalPath;

    static BootPlayMode()
    {
        EditorApplication.playModeStateChanged += OnPlayModeStateChanged;
    }

    private static void OnPlayModeStateChanged(PlayModeStateChange state)
    {
        switch (state)
        {
            case PlayModeStateChange.ExitingEditMode:
                HandleExitingEditMode();
                break;
            case PlayModeStateChange.EnteredPlayMode:
                HandleEnteredPlayMode();
                break;
            case PlayModeStateChange.EnteredEditMode:
                HandleEnteredEditMode();
                break;
        }
    }

    private static void HandleExitingEditMode()
    {
        string bootPath = FindBootScenePath();
        if (string.IsNullOrEmpty(bootPath))
        {
            Debug.Log("BootPlayMode: scene '_Boot' not found — Play will behave normally.");
            return;
        }

        if (!EditorSceneManager.SaveCurrentModifiedScenesIfUserWantsTo())
        {
            Debug.LogWarning("BootPlayMode: user canceled saving scenes — Play will behave normally.");
            return;
        }

        var active = EditorSceneManager.GetActiveScene();
        string activePath = active.path;
        if (string.IsNullOrEmpty(activePath))
        {
            Debug.LogWarning("BootPlayMode: active scene is not saved — cannot restore after Play.");
            return;
        }

        EditorPrefs.SetString(PrefOriginalScene, activePath);
        EditorPrefs.SetString(PrefBootPath, bootPath);

        Debug.Log($"BootPlayMode: saved original='{activePath}', boot='{bootPath}' to EditorPrefs.");

        var bootAsset = AssetDatabase.LoadAssetAtPath<SceneAsset>(bootPath);
        if (bootAsset != null)
        {
            EditorSceneManager.playModeStartScene = bootAsset;
            Debug.Log($"BootPlayMode: playModeStartScene set to '{bootPath}'.");
        }
    }

    private static void HandleEnteredPlayMode()
    {
        if (!EditorPrefs.HasKey(PrefOriginalScene))
        {
            EditorSceneManager.playModeStartScene = null;
            return;
        }

        string originalPath = EditorPrefs.GetString(PrefOriginalScene, string.Empty);
        if (string.IsNullOrEmpty(originalPath))
        {
            EditorSceneManager.playModeStartScene = null;
            return;
        }

        pendingOriginalPath = originalPath;
        Debug.Log($"BootPlayMode: EnteredPlayMode. pendingOriginalPath='{pendingOriginalPath}'");
        SceneManager.sceneLoaded += OnSceneLoadedInPlay;
        try
        {
            EditorSceneManager.LoadSceneInPlayMode(originalPath, new LoadSceneParameters(LoadSceneMode.Additive));
            Debug.Log($"BootPlayMode: requested additive load of '{originalPath}'.");
            // schedule a deferred unload attempt in case of timing issues
            EditorApplication.delayCall += TryUnloadBootDeferred;
        }
        catch (System.Exception ex)
        {
            Debug.LogError($"BootPlayMode: failed to load original scene in Play: {ex}");
            SceneManager.sceneLoaded -= OnSceneLoadedInPlay;
            pendingOriginalPath = null;
        }

        EditorSceneManager.playModeStartScene = null;
    }

    private static void OnSceneLoadedInPlay(Scene scene, LoadSceneMode mode)
    {
        if (string.IsNullOrEmpty(pendingOriginalPath))
            return;

        string expectedName = Path.GetFileNameWithoutExtension(pendingOriginalPath);
        if (!string.Equals(scene.path, pendingOriginalPath, System.StringComparison.OrdinalIgnoreCase) &&
            !string.Equals(scene.name, expectedName, System.StringComparison.OrdinalIgnoreCase))
            return; // not the scene we requested

        try { SceneManager.SetActiveScene(scene); } catch { }
        // Diagnostic: list loaded scenes
        var loadedList = new System.Text.StringBuilder();
        for (int i = 0; i < SceneManager.sceneCount; ++i)
        {
            var sc = SceneManager.GetSceneAt(i);
            loadedList.AppendFormat("[{0}] name='{1}' path='{2}' isLoaded={3}; ", i, sc.name, sc.path, sc.isLoaded);
        }
        Debug.Log("BootPlayMode: scenes after loading original: " + loadedList.ToString());

        // Try to unload any loaded scene that corresponds to _Boot.
        // Prefer the saved boot path (EditorPrefs) when available.
        string savedBootPath = EditorPrefs.GetString(PrefBootPath, string.Empty);
        bool unloadedAny = false;
        for (int i = 0; i < SceneManager.sceneCount; ++i)
        {
            var sc = SceneManager.GetSceneAt(i);
            if (!sc.IsValid() || !sc.isLoaded)
                continue;
            if (string.Equals(sc.path, scene.path, System.StringComparison.OrdinalIgnoreCase))
                continue; // don't unload the scene we just loaded

            string filename = Path.GetFileNameWithoutExtension(sc.path);
            bool matchBySavedPath = !string.IsNullOrEmpty(savedBootPath) && string.Equals(sc.path, savedBootPath, System.StringComparison.OrdinalIgnoreCase);
            bool matchByName = string.Equals(sc.name, BootSceneName, System.StringComparison.OrdinalIgnoreCase);
            bool matchByFilename = string.Equals(filename, BootSceneName, System.StringComparison.OrdinalIgnoreCase);
            bool matchByContains = (!string.IsNullOrEmpty(sc.name) && sc.name.IndexOf(BootSceneName, System.StringComparison.OrdinalIgnoreCase) >= 0)
                                   || (!string.IsNullOrEmpty(filename) && filename.IndexOf(BootSceneName, System.StringComparison.OrdinalIgnoreCase) >= 0);

            if (matchBySavedPath || matchByName || matchByFilename || matchByContains)
            {
                SceneManager.UnloadSceneAsync(sc);
                Debug.Log($"BootPlayMode: unloading scene '{sc.name}' (path: {sc.path}) detected as Boot.");
                unloadedAny = true;
            }
        }

        if (!unloadedAny)
            Debug.LogWarning("BootPlayMode: did not find any loaded scene matching _Boot to unload.");

        pendingOriginalPath = null;
        if (EditorPrefs.HasKey(PrefBootPath))
            EditorPrefs.DeleteKey(PrefBootPath);
        SceneManager.sceneLoaded -= OnSceneLoadedInPlay;
    }

    private static void TryUnloadBootDeferred()
    {
        // run once
        EditorApplication.delayCall -= TryUnloadBootDeferred;

        if (string.IsNullOrEmpty(pendingOriginalPath))
            return;

        var orig = SceneManager.GetSceneByPath(pendingOriginalPath);
        if (!orig.IsValid() || !orig.isLoaded)
            return; // not loaded yet; OnSceneLoadedInPlay will handle it later

        string savedBootPath = EditorPrefs.GetString(PrefBootPath, string.Empty);
        bool unloadedAny = false;
        for (int i = 0; i < SceneManager.sceneCount; ++i)
        {
            var sc = SceneManager.GetSceneAt(i);
            if (!sc.IsValid() || !sc.isLoaded)
                continue;
            if (string.Equals(sc.path, orig.path, System.StringComparison.OrdinalIgnoreCase))
                continue;

            string filename = Path.GetFileNameWithoutExtension(sc.path);
            bool matchBySavedPath = !string.IsNullOrEmpty(savedBootPath) && string.Equals(sc.path, savedBootPath, System.StringComparison.OrdinalIgnoreCase);
            bool matchByName = string.Equals(sc.name, BootSceneName, System.StringComparison.OrdinalIgnoreCase);
            bool matchByFilename = string.Equals(filename, BootSceneName, System.StringComparison.OrdinalIgnoreCase);

            if (matchBySavedPath || matchByName || matchByFilename)
            {
                SceneManager.UnloadSceneAsync(sc);
                Debug.Log($"BootPlayMode: (deferred) unloading scene '{sc.name}' (path: {sc.path}) detected as Boot.");
                unloadedAny = true;
            }
        }

        if (!unloadedAny)
            Debug.LogWarning("BootPlayMode: (deferred) did not find any loaded scene matching _Boot to unload.");

        pendingOriginalPath = null;
        if (EditorPrefs.HasKey(PrefBootPath))
            EditorPrefs.DeleteKey(PrefBootPath);
    }

    private static void HandleEnteredEditMode()
    {
        if (!EditorPrefs.HasKey(PrefOriginalScene))
            return;

        string originalPath = EditorPrefs.GetString(PrefOriginalScene, string.Empty);
        EditorPrefs.DeleteKey(PrefOriginalScene);
        if (EditorPrefs.HasKey(PrefBootPath))
            EditorPrefs.DeleteKey(PrefBootPath);
        if (string.IsNullOrEmpty(originalPath))
            return;

        EditorApplication.delayCall += () =>
        {
            try
            {
                if (AssetDatabase.LoadAssetAtPath<SceneAsset>(originalPath) != null || File.Exists(Path.GetFullPath(originalPath)))
                {
                    EditorSceneManager.OpenScene(originalPath, OpenSceneMode.Single);
                    Debug.Log($"BootPlayMode: restored editor scene '{originalPath}' after Stop.");
                }
                else
                {
                    Debug.LogWarning($"BootPlayMode: original scene '{originalPath}' not found when restoring in Editor.");
                }
            }
            catch (System.Exception ex)
            {
                Debug.LogError($"BootPlayMode: failed to restore original scene in Editor: {ex}");
            }
        };
    }

    private static string FindBootScenePath()
    {
        var guids = AssetDatabase.FindAssets("t:Scene");
        foreach (var g in guids)
        {
            string path = AssetDatabase.GUIDToAssetPath(g);
            string filename = Path.GetFileNameWithoutExtension(path);
            if (string.Equals(filename, BootSceneName, System.StringComparison.OrdinalIgnoreCase))
                return path;
        }
        return null;
    }
}

using System.IO;
using UnityEditor;
using UnityEditor.SceneManagement;
using UnityEngine;
using UnityEngine.SceneManagement;
using System;

// Clean BootPlayMode implementation
[InitializeOnLoad]
internal static class BootPlayMode
{
    private const string PrefOriginalScene = "BootPlayMode_OriginalScene";
    private const string PrefBootPath = "BootPlayMode_BootPath";
    private const string BootSceneName = "_Boot";
    private static string pendingOriginalPath;

    static BootPlayMode()
    {
        EditorApplication.playModeStateChanged += OnPlayModeStateChanged;
    }

    private static void OnPlayModeStateChanged(PlayModeStateChange state)
    {
        switch (state)
        {
            case PlayModeStateChange.ExitingEditMode:
                HandleExitingEditMode();
                break;
            case PlayModeStateChange.EnteredPlayMode:
                HandleEnteredPlayMode();
                break;
            case PlayModeStateChange.EnteredEditMode:
                HandleEnteredEditMode();
                break;
        }
    }

    private static void HandleExitingEditMode()
    {
        string bootPath = FindBootScenePath();
        if (string.IsNullOrEmpty(bootPath))
        {
            Debug.Log("BootPlayMode: scene '_Boot' not found — Play will behave normally.");
            return;
        }

        if (!EditorSceneManager.SaveCurrentModifiedScenesIfUserWantsTo())
        {
            Debug.LogWarning("BootPlayMode: user canceled saving scenes — Play will behave normally.");
            return;
        }

        var active = EditorSceneManager.GetActiveScene();
        string activePath = active.path;
        if (string.IsNullOrEmpty(activePath))
        {
            Debug.LogWarning("BootPlayMode: active scene is not saved — cannot restore after Play.");
            return;
        }

        EditorPrefs.SetString(PrefOriginalScene, activePath);
        EditorPrefs.SetString(PrefBootPath, bootPath);

        Debug.Log($"BootPlayMode: saved original='{activePath}', boot='{bootPath}' to EditorPrefs.");

        var bootAsset = AssetDatabase.LoadAssetAtPath<SceneAsset>(bootPath);
        if (bootAsset != null)
        {
            EditorSceneManager.playModeStartScene = bootAsset;
            Debug.Log($"BootPlayMode: playModeStartScene set to '{bootPath}'.");
        }
    }

    private static void HandleEnteredPlayMode()
    {
        if (!EditorPrefs.HasKey(PrefOriginalScene))
        {
            EditorSceneManager.playModeStartScene = null;
            return;
        }

        string originalPath = EditorPrefs.GetString(PrefOriginalScene, string.Empty);
        if (string.IsNullOrEmpty(originalPath))
        {
            EditorSceneManager.playModeStartScene = null;
            return;
        }

        pendingOriginalPath = originalPath;
        Debug.Log($"BootPlayMode: EnteredPlayMode. pendingOriginalPath='{pendingOriginalPath}'");
        SceneManager.sceneLoaded += OnSceneLoadedInPlay;
        try
        {
            EditorSceneManager.LoadSceneInPlayMode(originalPath, new LoadSceneParameters(LoadSceneMode.Additive));
            Debug.Log($"BootPlayMode: requested additive load of '{originalPath}'.");
            // schedule a deferred unload attempt in case of timing issues
            EditorApplication.delayCall += TryUnloadBootDeferred;
        }
        catch (System.Exception ex)
        {
            Debug.LogError($"BootPlayMode: failed to load original scene in Play: {ex}");
            SceneManager.sceneLoaded -= OnSceneLoadedInPlay;
            pendingOriginalPath = null;
        }

        EditorSceneManager.playModeStartScene = null;
    }

    private static void OnSceneLoadedInPlay(Scene scene, LoadSceneMode mode)
    {
        if (string.IsNullOrEmpty(pendingOriginalPath))
            return;

        string expectedName = Path.GetFileNameWithoutExtension(pendingOriginalPath);
        if (!string.Equals(scene.path, pendingOriginalPath, System.StringComparison.OrdinalIgnoreCase) &&
            !string.Equals(scene.name, expectedName, System.StringComparison.OrdinalIgnoreCase))
            return; // not the scene we requested

        try { SceneManager.SetActiveScene(scene); } catch { }
        // Diagnostic: list loaded scenes
        var loadedList = new System.Text.StringBuilder();
        for (int i = 0; i < SceneManager.sceneCount; ++i)
        {
            var sc = SceneManager.GetSceneAt(i);
            loadedList.AppendFormat("[{0}] name='{1}' path='{2}' isLoaded={3}; ", i, sc.name, sc.path, sc.isLoaded);
        }
        Debug.Log("BootPlayMode: scenes after loading original: " + loadedList.ToString());

        // Try to unload any loaded scene that corresponds to _Boot.
        // Prefer the saved boot path (EditorPrefs) when available.
        string savedBootPath = EditorPrefs.GetString(PrefBootPath, string.Empty);
        bool unloadedAny = false;
        for (int i = 0; i < SceneManager.sceneCount; ++i)
        {
            var sc = SceneManager.GetSceneAt(i);
            if (!sc.IsValid() || !sc.isLoaded)
                continue;
            if (string.Equals(sc.path, scene.path, StringComparison.OrdinalIgnoreCase))
                continue; // don't unload the scene we just loaded

            string filename = Path.GetFileNameWithoutExtension(sc.path);
            bool matchBySavedPath = !string.IsNullOrEmpty(savedBootPath) && string.Equals(sc.path, savedBootPath, StringComparison.OrdinalIgnoreCase);
            bool matchByName = string.Equals(sc.name, BootSceneName, StringComparison.OrdinalIgnoreCase);
            bool matchByFilename = string.Equals(filename, BootSceneName, StringComparison.OrdinalIgnoreCase);
            bool matchByContains = (!string.IsNullOrEmpty(sc.name) && sc.name.IndexOf(BootSceneName, StringComparison.OrdinalIgnoreCase) >= 0)
                                   || (!string.IsNullOrEmpty(filename) && filename.IndexOf(BootSceneName, StringComparison.OrdinalIgnoreCase) >= 0);

            // New: inspect scene contents for runtime marker components (GameManager/BootMarker)
            bool matchByMarker = SceneContainsBootMarker(sc);

            if (matchBySavedPath || matchByName || matchByFilename || matchByContains || matchByMarker)
            {
                SceneManager.UnloadSceneAsync(sc);
                Debug.Log($"BootPlayMode: unloading scene '{sc.name}' (path: {sc.path}) detected as Boot. matchBySavedPath={matchBySavedPath} matchByName={matchByName} matchByFilename={matchByFilename} matchByContains={matchByContains} matchByMarker={matchByMarker}");
                unloadedAny = true;
            }
        }

        if (!unloadedAny)
            Debug.LogWarning("BootPlayMode: did not find any loaded scene matching _Boot to unload.");

        pendingOriginalPath = null;
        if (EditorPrefs.HasKey(PrefBootPath))
            EditorPrefs.DeleteKey(PrefBootPath);
        SceneManager.sceneLoaded -= OnSceneLoadedInPlay;
    }

    private static void TryUnloadBootDeferred()
    {
        // run once
        EditorApplication.delayCall -= TryUnloadBootDeferred;

        if (string.IsNullOrEmpty(pendingOriginalPath))
            return;

        var orig = SceneManager.GetSceneByPath(pendingOriginalPath);
        if (!orig.IsValid() || !orig.isLoaded)
            return; // not loaded yet; OnSceneLoadedInPlay will handle it later

        string savedBootPath = EditorPrefs.GetString(PrefBootPath, string.Empty);
        bool unloadedAny = false;
        for (int i = 0; i < SceneManager.sceneCount; ++i)
        {
            var sc = SceneManager.GetSceneAt(i);
            if (!sc.IsValid() || !sc.isLoaded)
                continue;
            if (string.Equals(sc.path, orig.path, StringComparison.OrdinalIgnoreCase))
                continue;

            string filename = Path.GetFileNameWithoutExtension(sc.path);
            bool matchBySavedPath = !string.IsNullOrEmpty(savedBootPath) && string.Equals(sc.path, savedBootPath, StringComparison.OrdinalIgnoreCase);
            bool matchByName = string.Equals(sc.name, BootSceneName, StringComparison.OrdinalIgnoreCase);
            bool matchByFilename = string.Equals(filename, BootSceneName, StringComparison.OrdinalIgnoreCase);

            // New: also detect scenes that contain runtime boot marker (GameManager/BootMarker)
            bool matchByMarker = SceneContainsBootMarker(sc);

            if (matchBySavedPath || matchByName || matchByFilename || matchByMarker)
            {
                SceneManager.UnloadSceneAsync(sc);
                Debug.Log($"BootPlayMode: (deferred) unloading scene '{sc.name}' (path: {sc.path}) detected as Boot. matchBySavedPath={matchBySavedPath} matchByName={matchByName} matchByFilename={matchByFilename} matchByMarker={matchByMarker}");
                unloadedAny = true;
            }
        }

        if (!unloadedAny)
            Debug.LogWarning("BootPlayMode: (deferred) did not find any loaded scene matching _Boot to unload.");

        pendingOriginalPath = null;
        if (EditorPrefs.HasKey(PrefBootPath))
            EditorPrefs.DeleteKey(PrefBootPath);
    }

    // Helper: inspect scene root objects and their children for a GameManager/BootMarker marker
    private static bool SceneContainsBootMarker(Scene sc)
    {
        if (!sc.IsValid() || !sc.isLoaded)
            return false;
        try
        {
            var roots = sc.GetRootGameObjects();
            foreach (var go in roots)
            {
                if (go == null)
                    continue;

                // 1) Name-based detection
                if (string.Equals(go.name, "GameManager", StringComparison.OrdinalIgnoreCase) ||
                    string.Equals(go.name, "BootMarker", StringComparison.OrdinalIgnoreCase))
                    return true;

                // 2) Component name detection on root
                if (go.GetComponent("GameManager") != null || go.GetComponent("BootMarker") != null)
                    return true;

                // 3) Scan children
                var transforms = go.GetComponentsInChildren<Transform>(true);
                foreach (var t in transforms)
                {
                    if (t == null || t.gameObject == null)
                        continue;
                    if (string.Equals(t.name, "GameManager", StringComparison.OrdinalIgnoreCase) ||
                        string.Equals(t.name, "BootMarker", StringComparison.OrdinalIgnoreCase))
                        return true;
                    if (t.gameObject.GetComponent("GameManager") != null || t.gameObject.GetComponent("BootMarker") != null)
                        return true;
                }
            }
        }
        catch { }
        return false;
    }

    private static void HandleEnteredEditMode()
    {
        if (!EditorPrefs.HasKey(PrefOriginalScene))
            return;

        string originalPath = EditorPrefs.GetString(PrefOriginalScene, string.Empty);
        EditorPrefs.DeleteKey(PrefOriginalScene);
        if (EditorPrefs.HasKey(PrefBootPath))
            EditorPrefs.DeleteKey(PrefBootPath);
        if (string.IsNullOrEmpty(originalPath))
            return;

        EditorApplication.delayCall += () =>
        {
            try
            {
                if (AssetDatabase.LoadAssetAtPath<SceneAsset>(originalPath) != null || File.Exists(Path.GetFullPath(originalPath)))
                {
                    EditorSceneManager.OpenScene(originalPath, OpenSceneMode.Single);
                    Debug.Log($"BootPlayMode: restored editor scene '{originalPath}' after Stop.");
                }
                else
                {
                    Debug.LogWarning($"BootPlayMode: original scene '{originalPath}' not found when restoring in Editor.");
                }
            }
            catch (System.Exception ex)
            {
                Debug.LogError($"BootPlayMode: failed to restore original scene in Editor: {ex}");
            }
        };
    }

    private static string FindBootScenePath()
    {
        var guids = AssetDatabase.FindAssets("t:Scene");
        foreach (var g in guids)
        {
            string path = AssetDatabase.GUIDToAssetPath(g);
            string filename = Path.GetFileNameWithoutExtension(path);
            if (string.Equals(filename, BootSceneName, System.StringComparison.OrdinalIgnoreCase))
                return path;
        }
        return null;
    }
}

using UnityEditor;
using UnityEditor.SceneManagement;
using UnityEngine;
using System.IO;

[InitializeOnLoad]
public static class BootPlayModeInterceptor
{
    private const string BootSceneName = "_Boot";
    private const string ResourcesFolder = "Assets/Resources";
    private const string ResourceAssetPath = "Assets/Resources/BootSceneTarget.asset";

    static BootPlayModeInterceptor()
    {
        EditorApplication.playModeStateChanged += OnPlayModeStateChanged;
    }

    private static void OnPlayModeStateChanged(PlayModeStateChange state)
    {
        if (state == PlayModeStateChange.ExitingEditMode)
        {
            // Before entering Play, find the _Boot scene asset
            var bootGuid = AssetDatabase.FindAssets("t:Scene " + BootSceneName);
            if (bootGuid == null || bootGuid.Length == 0)
            {
                if (!EditorUtility.DisplayDialog("_Boot scene not found", "No scene named '_Boot' was found in the project. Cancel Play or create an _Boot scene.", "Cancel Play", "Continue Anyway"))
                {
                    // Cancel play: abort by returning to Edit mode
                    EditorApplication.isPlaying = false;
                    return;
                }
                else
                {
                    // Continue without setting a start scene
                    return;
                }
            }

            // Use the first match
            var bootPath = AssetDatabase.GUIDToAssetPath(bootGuid[0]);
            var bootSceneAsset = AssetDatabase.LoadAssetAtPath<SceneAsset>(bootPath);
            if (bootSceneAsset == null)
            {
                Debug.LogError("BootPlayModeInterceptor: Failed to load SceneAsset for _Boot.");
                return;
            }

            // Save the currently active scene path into a ScriptableObject under Resources
            var activeScene = UnityEditor.SceneManagement.EditorSceneManager.GetActiveScene();
            var targetPath = activeScene.path; // e.g. Assets/Scenes/Level1.unity
            var targetName = Path.GetFileNameWithoutExtension(targetPath);

            // Ensure Resources folder exists
            if (!AssetDatabase.IsValidFolder(ResourcesFolder))
            {
                AssetDatabase.CreateFolder("Assets", "Resources");
            }

            BootSceneTarget asset = AssetDatabase.LoadAssetAtPath<BootSceneTarget>(ResourceAssetPath);
            if (asset == null)
            {
                asset = ScriptableObject.CreateInstance<BootSceneTarget>();
                AssetDatabase.CreateAsset(asset, ResourceAssetPath);
            }

            asset.TargetScenePath = targetPath;
            asset.TargetSceneName = targetName;
            EditorUtility.SetDirty(asset);
            AssetDatabase.SaveAssets();

            // Set the playModeStartScene to _Boot
            UnityEditor.SceneManagement.EditorSceneManager.playModeStartScene = bootSceneAsset;
            Debug.Log($"BootPlayModeInterceptor: Starting Play from '{bootPath}', saved target '{targetPath}'.");
        }

        if (state == PlayModeStateChange.EnteredEditMode)
        {
            // Clear the custom start scene after exiting Play
            UnityEditor.SceneManagement.EditorSceneManager.playModeStartScene = null;
            // Optionally, remove or clear the resources asset
            var asset = AssetDatabase.LoadAssetAtPath<BootSceneTarget>(ResourceAssetPath);
            if (asset != null)
            {
                asset.TargetScenePath = string.Empty;
                asset.TargetSceneName = string.Empty;
                EditorUtility.SetDirty(asset);
                AssetDatabase.SaveAssets();
            }
        }
    }
}

using UnityEditor;
using UnityEditor.SceneManagement;
using UnityEngine;
using System.IO;

[InitializeOnLoad]
public static class BootPlayModeInterceptor
{
    private const string BootSceneName = "_Boot";
    private const string ResourcesFolder = "Assets/Resources";
    private const string ResourceAssetPath = "Assets/Resources/BootSceneTarget.asset";

    static BootPlayModeInterceptor()
    {
        EditorApplication.playModeStateChanged += OnPlayModeStateChanged;
    }

    private static void OnPlayModeStateChanged(PlayModeStateChange state)
    {
        if (state == PlayModeStateChange.ExitingEditMode)
        {
            // Before entering Play, locate the _Boot scene asset by filename to be robust
            var guids = AssetDatabase.FindAssets("t:Scene");
            string bootPath = null;
            foreach (var g in guids)
            {
                var p = AssetDatabase.GUIDToAssetPath(g);
                var filename = System.IO.Path.GetFileNameWithoutExtension(p);
                if (string.Equals(filename, BootSceneName, System.StringComparison.OrdinalIgnoreCase))
                {
                    bootPath = p;
                    break;
                }
            }

            if (string.IsNullOrEmpty(bootPath))
            {
                if (!EditorUtility.DisplayDialog("_Boot scene not found", "No scene named '_Boot' was found in the project. Cancel Play or create an _Boot scene.", "Cancel Play", "Continue Anyway"))
                {
                    // Cancel play: abort by returning to Edit mode
                    EditorApplication.isPlaying = false;
                    return;
                }
                else
                {
                    // Continue without setting a start scene
                    return;
                }
            }

            var bootSceneAsset = AssetDatabase.LoadAssetAtPath<SceneAsset>(bootPath);
            if (bootSceneAsset == null)
            {
                Debug.LogError("BootPlayModeInterceptor: Failed to load SceneAsset for _Boot.");
                return;
            }

            // Save the currently active scene path into a ScriptableObject under Resources
            var activeScene = UnityEditor.SceneManagement.EditorSceneManager.GetActiveScene();
            var targetPath = activeScene.path; // e.g. Assets/Scenes/Level1.unity
            var targetName = Path.GetFileNameWithoutExtension(targetPath);

            // If the user started Play while already on the _Boot scene, override the target to Splash
            if (string.Equals(targetName, BootSceneName, System.StringComparison.OrdinalIgnoreCase))
            {
                targetPath = string.Empty;
                targetName = "Splash";
            }

            // Ensure Resources folder exists
            if (!AssetDatabase.IsValidFolder(ResourcesFolder))
            {
                AssetDatabase.CreateFolder("Assets", "Resources");
            }

            BootSceneTarget asset = AssetDatabase.LoadAssetAtPath<BootSceneTarget>(ResourceAssetPath);
            if (asset == null)
            {
                asset = ScriptableObject.CreateInstance<BootSceneTarget>();
                AssetDatabase.CreateAsset(asset, ResourceAssetPath);
            }

            asset.TargetScenePath = targetPath;
            asset.TargetSceneName = targetName;
            EditorUtility.SetDirty(asset);
            AssetDatabase.SaveAssets();

            // Set the playModeStartScene to _Boot
            UnityEditor.SceneManagement.EditorSceneManager.playModeStartScene = bootSceneAsset;
            Debug.Log($"BootPlayModeInterceptor: Starting Play from '{bootPath}', saved target '{targetName}' (path '{targetPath}').");
        }

        if (state == PlayModeStateChange.EnteredEditMode)
        {
            // Clear the custom start scene after exiting Play
            UnityEditor.SceneManagement.EditorSceneManager.playModeStartScene = null;
            // Optionally, remove or clear the resources asset
            var asset = AssetDatabase.LoadAssetAtPath<BootSceneTarget>(ResourceAssetPath);
            if (asset != null)
            {
                asset.TargetScenePath = string.Empty;
                asset.TargetSceneName = string.Empty;
                EditorUtility.SetDirty(asset);
                AssetDatabase.SaveAssets();
            }
        }
    }
}

using UnityEditor;
using UnityEngine;

[InitializeOnLoad]
internal static class EnsureBootSceneTarget
{
    private const string ResourceAssetPath = "Assets/Resources/BootSceneTarget.asset";

    static EnsureBootSceneTarget()
    {
        EditorApplication.delayCall += EnsureAssetExists;
    }

    private static void EnsureAssetExists()
    {
        var asset = AssetDatabase.LoadAssetAtPath<BootSceneTarget>(ResourceAssetPath);
        if (asset == null)
        {
            var instance = ScriptableObject.CreateInstance<BootSceneTarget>();
            instance.TargetSceneName = "Splash";
            // create Resources folder if missing
            if (!AssetDatabase.IsValidFolder("Assets/Resources"))
                AssetDatabase.CreateFolder("Assets", "Resources");
            AssetDatabase.CreateAsset(instance, ResourceAssetPath);
            AssetDatabase.SaveAssets();
            Debug.Log("EnsureBootSceneTarget: Created Resources/BootSceneTarget.asset with TargetSceneName='Splash'.");
        }
        // Also ensure the _Boot scene contains a BootSceneLoader GameObject so the redirect will run in Play.
        EnsureBootSceneHasLoader();
    }

    private static void EnsureBootSceneHasLoader()
    {
        // Find boot scene path
        var guids = AssetDatabase.FindAssets("t:Scene");
        string bootPath = null;
        foreach (var g in guids)
        {
            var p = AssetDatabase.GUIDToAssetPath(g);
            var filename = System.IO.Path.GetFileNameWithoutExtension(p);
            if (string.Equals(filename, "_Boot", System.StringComparison.OrdinalIgnoreCase))
            {
                bootPath = p;
                break;
            }
        }
        if (string.IsNullOrEmpty(bootPath))
        {
            Debug.LogWarning("EnsureBootSceneTarget: _Boot scene not found in project.");
            return;
        }

        // Remember current scene
        var active = UnityEditor.SceneManagement.EditorSceneManager.GetActiveScene();

        // Open boot scene additively to modify
        var scene = UnityEditor.SceneManagement.EditorSceneManager.OpenScene(bootPath, UnityEditor.SceneManagement.OpenSceneMode.Additive);
        if (!scene.IsValid())
        {
            Debug.LogWarning($"EnsureBootSceneTarget: failed to open _Boot scene at '{bootPath}'.");
            return;
        }

        bool changed = false;
        // Check for existing BootSceneLoader
        var rootGOs = scene.GetRootGameObjects();
        bool hasLoader = false;
        foreach (var go in rootGOs)
        {
            if (go.GetComponent<BootSceneLoader>() != null)
            {
                hasLoader = true;
                break;
            }
        }

        if (!hasLoader)
        {
            var go = new GameObject("BootRunner");
            go.AddComponent<BootSceneLoader>();
            UnityEditor.SceneManagement.EditorSceneManager.MoveGameObjectToScene(go, scene);
            changed = true;
            Debug.Log("EnsureBootSceneTarget: Added BootSceneLoader to _Boot scene.");
        }

        // Optionally ensure there's a GameManagerCore/GameManager present
        bool hasGM = false;
        rootGOs = scene.GetRootGameObjects();
        foreach (var go in rootGOs)
        {
            if (go.GetComponent<GameManagerCore>() != null || go.GetComponent("GameManager") != null)
            {
                hasGM = true;
                break;
            }
        }
        if (!hasGM)
        {
            var go = new GameObject("GameManager");
            go.AddComponent<GameManagerCore>();
            UnityEditor.SceneManagement.EditorSceneManager.MoveGameObjectToScene(go, scene);
            changed = true;
            Debug.Log("EnsureBootSceneTarget: Added GameManagerCore to _Boot scene.");
        }

        if (changed)
        {
            UnityEditor.SceneManagement.EditorSceneManager.MarkSceneDirty(scene);
            UnityEditor.SceneManagement.EditorSceneManager.SaveScene(scene);
            Debug.Log("EnsureBootSceneTarget: _Boot scene updated and saved.");
        }

        // Close the additive scene and restore active
        UnityEditor.SceneManagement.EditorSceneManager.CloseScene(scene, true);
        UnityEditor.SceneManagement.EditorSceneManager.OpenScene(active.path, UnityEditor.SceneManagement.OpenSceneMode.Single);
    }
}

using System.Collections;
using UnityEngine;
using UnityEngine.SceneManagement;

public class BootSceneLoader : MonoBehaviour
{
    private IEnumerator Start()
    {
        // Load the BootSceneTarget from Resources
        var target = Resources.Load<BootSceneTarget>("BootSceneTarget");
        if (target == null || string.IsNullOrEmpty(target.TargetSceneName))
        {
            Debug.LogError("BootSceneLoader: No BootSceneTarget found in Resources or target scene name is empty. Ensure the editor created Assets/Resources/BootSceneTarget.asset before Play.");
            yield break;
        }

        // If the target is the Boot scene itself, do nothing
        var currentScene = SceneManager.GetActiveScene();
        if (string.Equals(currentScene.name, target.TargetSceneName, System.StringComparison.OrdinalIgnoreCase))
        {
            Debug.Log("BootSceneLoader: Target scene is the Boot scene itself. Nothing to load.");
            yield break;
        }

        // Load the target scene additively
        var loadOp = SceneManager.LoadSceneAsync(target.TargetSceneName, LoadSceneMode.Additive);
        if (loadOp == null)
        {
            Debug.LogError($"BootSceneLoader: Failed to start loading scene '{target.TargetSceneName}'. Ensure it is added to Build Settings and the name is correct.");
            yield break;
        }

        while (!loadOp.isDone)
            yield return null;

        // Optionally, set the newly loaded scene as active
        var loadedScene = SceneManager.GetSceneByName(target.TargetSceneName);
        if (loadedScene.IsValid())
            SceneManager.SetActiveScene(loadedScene);

        // Unload the Boot scene
        var unloadOp = SceneManager.UnloadSceneAsync(currentScene);
        if (unloadOp == null)
        {
            Debug.LogWarning("BootSceneLoader: Failed to unload Boot scene.");
            yield break;
        }

        while (!unloadOp.isDone)
            yield return null;

        Debug.Log($"BootSceneLoader: Loaded '{target.TargetSceneName}' and unloaded Boot scene.");
    }
}

using System.Collections;
using UnityEngine;
using UnityEngine.SceneManagement;
using System;
using System.Reflection;

public class BootSceneLoader : MonoBehaviour
{
    private IEnumerator Start()
    {
        // Load the BootSceneTarget from Resources
        var target = Resources.Load<BootSceneTarget>("BootSceneTarget");
        string targetName = "Splash";
        if (target != null && !string.IsNullOrEmpty(target.TargetSceneName))
            targetName = target.TargetSceneName;
        else
            Debug.LogWarning("BootSceneLoader: BootSceneTarget missing or empty; defaulting target to 'Splash'.");

        // If the target is the Boot scene itself, do nothing
        var currentScene = SceneManager.GetActiveScene();
        if (string.Equals(currentScene.name, targetName, StringComparison.OrdinalIgnoreCase))
        {
            Debug.Log("BootSceneLoader: Target scene is the Boot scene itself. Nothing to load.");
            yield break;
        }

        // Try to find a manager object that centralizes SceneManager access.
        // We'll look for any MonoBehaviour whose type name is 'GameManager' or 'GameManagerCore'
        float timeout = 1.0f;
        float t = 0f;
        bool delegated = false;
        while (t < timeout)
        {
            var mbs = UnityEngine.Object.FindObjectsOfType<MonoBehaviour>();
            foreach (var mb in mbs)
            {
                if (mb == null) continue;
                var typeName = mb.GetType().Name;
                if (string.Equals(typeName, "GameManager", StringComparison.Ordinal) || string.Equals(typeName, "GameManagerCore", StringComparison.Ordinal))
                {
                    // Try to find a StartBootLoad method
                    var mi = mb.GetType().GetMethod("StartBootLoad", BindingFlags.Instance | BindingFlags.Public | BindingFlags.NonPublic);
                    if (mi != null)
                    {
                        try
                        {
                            mi.Invoke(mb, new object[] { targetName });
                            Debug.Log($"BootSceneLoader: Delegated boot loading to '{typeName}'.");
                            delegated = true;
                            break;
                        }
                        catch (Exception ex)
                        {
                            Debug.LogWarning($"BootSceneLoader: Failed invoking StartBootLoad on {typeName}: {ex}");
                        }
                    }
                }
            }
            if (delegated) break;
            yield return null;
            t += Time.deltaTime;
        }

        if (delegated)
        {
            yield break; // manager will perform loading/unloading
        }

        // Fallback: perform additive load ourselves and unload the Boot scene
        Debug.Log($"BootSceneLoader: No GameManager found; fallback loading '{targetName}' additively.");
        var loadOp = SceneManager.LoadSceneAsync(targetName, LoadSceneMode.Additive);
        if (loadOp == null)
        {
            Debug.LogError($"BootSceneLoader: Failed to start loading scene '{targetName}'. Ensure it is added to Build Settings and the name is correct.");
            yield break;
        }
        while (!loadOp.isDone) yield return null;

        var loadedScene = SceneManager.GetSceneByName(targetName);
        if (loadedScene.IsValid()) SceneManager.SetActiveScene(loadedScene);

        var unloadOp = SceneManager.UnloadSceneAsync(currentScene);
        if (unloadOp == null)
        {
            Debug.LogWarning("BootSceneLoader: Failed to unload Boot scene.");
            yield break;
        }
        while (!unloadOp.isDone) yield return null;

        Debug.Log($"BootSceneLoader: Loaded '{targetName}' and unloaded Boot scene.");
    }
}

