using System;
using System.Collections;
using UnityEngine;
using UnityEngine.SceneManagement;
#if ENABLE_INPUT_SYSTEM
using UnityEngine.InputSystem;
using UnityEngine.InputSystem.Users;
#endif

/// <summary>
/// GameManager singleton:
/// - Centraliza todo acesso ao SceneManager (apenas esta classe deve trocar cenas)
/// - Mantém o estado do jogo (enum simplificado)
/// - Aloca inputs para o jogador (suporte ao Input System é opcional/condicional)
/// Coloque este script em uma cena inicial (por exemplo a cena _Boot) ou ele será criado automaticamente no primeiro carregamento.
/// </summary>
public class GameManager : MonoBehaviour
{
    public enum GameState
    {
        Iniciando,
        MenuPrincipal,
        Gameplay,
        // adicione mais estados se necessário
    }

    private static GameManager _instance;
    public static GameManager Instance
    {
        get
        {
            if (_instance == null)
            {
                // try to find existing in scene (use FindFirstObjectByType to avoid deprecated API)
#if UNITY_2022_2_OR_NEWER
                _instance = FindFirstObjectByType<GameManager>();
#else
                _instance = FindObjectOfType<GameManager>();
#endif
                if (_instance == null)
                {
                    var go = new GameObject("GameManager");
                    _instance = go.AddComponent<GameManager>();
                }
            }
            return _instance;
        }
    }

    [Header("Debug")]
    [SerializeField]
    private GameState initialState = GameState.Iniciando;

    public GameState State { get; private set; }

    public event Action<GameState> OnStateChanged;

    private bool _isLoadingScene;

    private void Awake()
    {
        if (_instance != null && _instance != this)
        {
            Destroy(this.gameObject);
            return;
        }
        _instance = this;
        DontDestroyOnLoad(this.gameObject);

        State = initialState;
    }

    private void Start()
    {
        Debug.Log($"GameManager started. State={State}");
    }

    private void OnEnable()
    {
        SceneManager.sceneLoaded += OnSceneLoaded;
        // set initial state based on currently active scene
        var active = SceneManager.GetActiveScene();
        MapSceneToState(active.name);
    }

    private void OnDisable()
    {
        SceneManager.sceneLoaded -= OnSceneLoaded;
    }

    private void OnSceneLoaded(Scene scene, LoadSceneMode mode)
    {
        MapSceneToState(scene.name);
    }

    private void MapSceneToState(string sceneName)
    {
        // Map specific scene names to game states
        switch (sceneName)
        {
            case "_Boot":
                SetState(GameState.Iniciando);
                break;
            case "MenuPrincipal":
                SetState(GameState.MenuPrincipal);
                break;
            case "SampleScene":
                SetState(GameState.Gameplay);
                break;
            // unlisted scenes keep the current state (e.g., Splash)
        }
    }

    /// <summary>
    /// Solicita uma mudança de cena. Apenas o GameManager chama SceneManager.
    /// Retorna true se a mudança foi iniciada.
    /// </summary>
    public bool RequestSceneChange(string sceneName)
    {
        if (_isLoadingScene)
        {
            Debug.LogWarning("GameManager: já está carregando uma cena.");
            return false;
        }

        // método simples de autorização: não permite troca quando estamos iniciando
        if (State == GameState.Iniciando)
        {
            Debug.LogWarning($"GameManager: mudança para '{sceneName}' negada — estado atual: {State}");
            return false;
        }

        StartCoroutine(LoadSceneCoroutine(sceneName, LoadSceneMode.Single));
        return true;
    }

    /// <summary>
    /// Força a troca de cena independentemente do estado.
    /// </summary>
    public void ForceSceneChange(string sceneName)
    {
        if (_isLoadingScene)
        {
            Debug.LogWarning("GameManager: já está carregando uma cena.");
            return;
        }
        StartCoroutine(LoadSceneCoroutine(sceneName, LoadSceneMode.Single));
    }

    /// <summary>
    /// Troca o estado do jogo e notifica ouvintes.
    /// </summary>
    public void SetState(GameState newState)
    {
        if (State == newState) return;
        State = newState;
        Debug.Log($"GameManager: estado alterado para {State}");
        OnStateChanged?.Invoke(State);
    }

    private IEnumerator LoadSceneCoroutine(string sceneName, LoadSceneMode mode)
    {
        _isLoadingScene = true;

        Debug.Log($"GameManager: carregando cena '{sceneName}' (mode={mode})...");
        AsyncOperation op = SceneManager.LoadSceneAsync(sceneName, mode);
        if (op == null)
        {
            Debug.LogError($"GameManager: cena '{sceneName}' não encontrada ou LoadSceneAsync retornou null.");
            _isLoadingScene = false;
            yield break;
        }

        // aguarda término
        while (!op.isDone)
            yield return null;

        // pequena espera para garantir que objetos Awake/OnEnable já rodaram
        yield return null;

        // após carregar, alocar entradas para jogador(s)
        try
        {
            AllocateInputToPlayer();
        }
        catch (Exception ex)
        {
            Debug.LogWarning($"GameManager: falha ao alocar inputs: {ex}");
        }

        _isLoadingScene = false;
        Debug.Log($"GameManager: cena '{sceneName}' carregada.");
    }

    /// <summary>
    /// Called from a Boot scene to load the real target scene additively and then unload the Boot scene.
    /// This ensures only GameManager touches SceneManager.
    /// </summary>
    public void StartBootLoad(string targetSceneName)
    {
        if (_isLoadingScene)
        {
            Debug.LogWarning("GameManager: já está carregando uma cena.");
            return;
        }
        StartCoroutine(LoadSceneFromBootCoroutine(targetSceneName));
    }

    private IEnumerator LoadSceneFromBootCoroutine(string targetSceneName)
    {
        _isLoadingScene = true;

        var currentScene = SceneManager.GetActiveScene();
        Debug.Log($"GameManager: Boot sequence — carregando '{targetSceneName}' additivamente...");
        var loadOp = SceneManager.LoadSceneAsync(targetSceneName, LoadSceneMode.Additive);
        if (loadOp == null)
        {
            Debug.LogError($"GameManager: falha ao iniciar carregamento de '{targetSceneName}'.");
            _isLoadingScene = false;
            yield break;
        }

        while (!loadOp.isDone)
            yield return null;

        var loadedScene = SceneManager.GetSceneByName(targetSceneName);
        if (loadedScene.IsValid())
            SceneManager.SetActiveScene(loadedScene);

        // unload the boot scene
        var unloadOp = SceneManager.UnloadSceneAsync(currentScene);
        if (unloadOp != null)
        {
            while (!unloadOp.isDone)
                yield return null;
        }

        // allow inputs to be allocated in the newly loaded scene
        yield return null;
        AllocateInputToPlayer();

        _isLoadingScene = false;
        Debug.Log($"GameManager: Boot sequence complete. Loaded '{targetSceneName}'.");
    }

    /// <summary>
    /// Aloca o primeiro dispositivo disponível ao primeiro PlayerInput encontrado.
    /// Esse código só é compilado se o Input System estiver disponível (símbolo ENABLE_INPUT_SYSTEM).
    /// Implementação simples adequada para single-player.
    /// </summary>
    private void AllocateInputToPlayer()
    {
#if ENABLE_INPUT_SYSTEM
        var devices = InputSystem.devices;
        if (devices.Count == 0)
        {
            Debug.Log("GameManager: nenhum dispositivo do Input System detectado.");
            return;
        }

        // Use PlayerInput.all to avoid obsolete FindObjectOfType usage
        var allPlayers = PlayerInput.all;
        PlayerInput player = null;
        if (allPlayers.Count > 0)
            player = allPlayers[0];

        if (player == null)
        {
            Debug.Log("GameManager: nenhum PlayerInput encontrado na cena.");
            return;
        }

        var firstDevice = devices[0];

        try
        {
            var user = player.user;
            if (!user.valid)
            {
                user = InputUser.PerformPairingWithDevice(firstDevice);
            }

            try
            {
                player.SwitchCurrentControlScheme(player.currentControlScheme, firstDevice);
            }
            catch (Exception)
            {
                InputUser.PerformPairingWithDevice(firstDevice, user);
            }

            Debug.Log($"GameManager: device '{firstDevice}' alocado ao PlayerInput '{player.gameObject.name}'.");
        }
        catch (Exception ex)
        {
            Debug.LogWarning($"GameManager: erro ao alocar dispositivo: {ex}");
        }
#else
        Debug.Log("GameManager: Input System não habilitado — pulando alocação de inputs.");
#endif
    }
}

using System.Collections;
using UnityEngine;
using UnityEngine.SceneManagement;

#if ENABLE_INPUT_SYSTEM
using UnityEngine.InputSystem;
using UnityEngine.InputSystem.Users;
#endif

/// <summary>
/// GameManagerCore: core implementation of a GameManager singleton. If a user-defined
/// GameManager.cs exists, it will be a separate class; this file provides the behavior
/// requested in the task under a different name to avoid collisions.
/// Place this component on a GameObject named 'GameManager' in the _Boot scene.
/// </summary>
public class GameManagerCore : MonoBehaviour
{
    public enum GameState { Iniciando, MenuPrincipal, Gameplay }

    private static GameManagerCore _instance;
    public static GameManagerCore Instance => _instance;

    [Header("Optional PlayerInput holder (assign GameObject with PlayerInput)")]
    public MonoBehaviour playerInputHolder;

    private GameState _state = GameState.Iniciando;

    private void Awake()
    {
        if (_instance != null && _instance != this)
        {
            Destroy(gameObject);
            return;
        }
        _instance = this;
        DontDestroyOnLoad(gameObject);
        Debug.Log("GameManagerCore: Awake - instance created. State=" + _state);
    }

    private void Start()
    {
        SetState(GameState.Iniciando);
#if ENABLE_INPUT_SYSTEM
        AllocateInputToPlayer();
#else
        Debug.Log("GameManagerCore: Input System not enabled or unavailable.");
#endif
    }

    private void SetState(GameState newState)
    {
        if (_state == newState) return;
        Debug.Log($"GameManagerCore: State change {_state} -> {newState}");
        _state = newState;
    }

    public void ForceSceneChange(string sceneName)
    {
        if (string.IsNullOrEmpty(sceneName))
        {
            Debug.LogWarning("GameManagerCore.ForceSceneChange: empty sceneName");
            return;
        }
        StartCoroutine(DoForceSceneChange(sceneName));
    }

    private IEnumerator DoForceSceneChange(string sceneName)
    {
        var op = SceneManager.LoadSceneAsync(sceneName, LoadSceneMode.Single);
        if (op == null)
        {
            Debug.LogError($"GameManagerCore: Failed to start loading scene '{sceneName}'. Ensure it's in Build Settings.");
            yield break;
        }
        while (!op.isDone) yield return null;

        if (sceneName.ToLowerInvariant().Contains("menu")) SetState(GameState.MenuPrincipal);
        else if (sceneName.ToLowerInvariant().Contains("sample") || sceneName.ToLowerInvariant().Contains("game")) SetState(GameState.Gameplay);
        else Debug.Log($"GameManagerCore: Scene '{sceneName}' loaded. State remains {_state}.");
    }

    public void RequestSceneChange(string sceneName) => ForceSceneChange(sceneName);

    public void StartBootLoad(string targetSceneName)
    {
        if (string.IsNullOrEmpty(targetSceneName)) { Debug.LogError("GameManagerCore.StartBootLoad: empty target"); return; }
        StartCoroutine(BootLoadCoroutine(targetSceneName));
    }

    private IEnumerator BootLoadCoroutine(string targetSceneName)
    {
        Debug.Log($"GameManagerCore: Boot loading target '{targetSceneName}'");
        var loadOp = SceneManager.LoadSceneAsync(targetSceneName, LoadSceneMode.Additive);
        if (loadOp == null) { Debug.LogError($"GameManagerCore: Failed to start loading scene '{targetSceneName}'."); yield break; }
        while (!loadOp.isDone) yield return null;

        var loadedScene = SceneManager.GetSceneByName(targetSceneName);
        if (loadedScene.IsValid()) SceneManager.SetActiveScene(loadedScene);

        for (int i = 0; i < SceneManager.sceneCount; ++i)
        {
            var sc = SceneManager.GetSceneAt(i);
            if (!sc.IsValid() || !sc.isLoaded) continue;
            if (string.Equals(sc.name, targetSceneName, System.StringComparison.OrdinalIgnoreCase)) continue;

            string filename = System.IO.Path.GetFileNameWithoutExtension(sc.path);
            bool isBootName = string.Equals(sc.name, "_Boot", System.StringComparison.OrdinalIgnoreCase) || string.Equals(filename, "_Boot", System.StringComparison.OrdinalIgnoreCase);
            bool containsGM = SceneContainsGameManager(sc);
            if (isBootName || containsGM)
            {
                Debug.Log($"GameManagerCore: Unloading boot scene '{sc.name}' (containsGM={containsGM})");
                SceneManager.UnloadSceneAsync(sc);
            }
        }

        if (targetSceneName.ToLowerInvariant().Contains("menu")) SetState(GameState.MenuPrincipal);
        else SetState(GameState.Gameplay);
    }

    private bool SceneContainsGameManager(Scene sc)
    {
        if (!sc.IsValid() || !sc.isLoaded) return false;
        try
        {
            var roots = sc.GetRootGameObjects();
            foreach (var go in roots)
            {
                if (go == null) continue;
                if (go.GetComponent<GameManagerCore>() != null) return true;
                if (go.GetComponentInChildren<GameManagerCore>(true) != null) return true;
            }
        }
        catch { }
        return false;
    }

#if ENABLE_INPUT_SYSTEM
    private void AllocateInputToPlayer()
    {
        if (playerInputHolder == null) { Debug.Log("GameManagerCore: No playerInputHolder assigned."); return; }
        var pi = playerInputHolder.GetComponent<UnityEngine.InputSystem.PlayerInput>();
        if (pi == null) { Debug.Log("GameManagerCore: playerInputHolder has no PlayerInput."); return; }
        var devices = InputSystem.devices;
        if (devices.Count == 0) { Debug.Log("GameManagerCore: No devices available."); return; }
        var device = devices[0];
        try { InputUser.PerformPairingWithDevice(device, pi.user); Debug.Log($"GameManagerCore: Paired '{device.displayName}' to PlayerInput."); }
        catch (System.Exception ex) { Debug.LogWarning($"GameManagerCore: Failed to pair device: {ex}"); }
    }
#endif
}

using UnityEngine;

/// <summary>
/// Simple UI controller for the main menu. Attach to a GameObject in the MenuPrincipal scene
/// and wire the OnStartClicked and OnQuitClicked methods to the respective UI buttons.
/// </summary>
public class MenuUiController : MonoBehaviour
{
    public void OnStartClicked()
    {
        if (GameManager.Instance != null)
        {
            GameManager.Instance.RequestSceneChange("SampleScene");
        }
        else
        {
            Debug.LogWarning("MenuUiController: GameManager not found. Loading SampleScene directly.");
            UnityEngine.SceneManagement.SceneManager.LoadScene("SampleScene");
        }
    }

    public void OnQuitClicked()
    {
        Debug.Log("MenuUiController: Quit requested.");
        Application.Quit();
    }
}

using System.Collections;
using UnityEngine;

/// <summary>
/// Controls the Splash scene. Shows the splash image for a fixed duration and then
/// requests a transition to the MenuPrincipal scene via GameManager.
/// </summary>
public class SplashController : MonoBehaviour
{
    [Tooltip("Tempo em segundos que a splash ficará visível")]
    public float displaySeconds = 2f;

    private IEnumerator Start()
    {
        // Wait for the UI to render
        yield return null;

        // Wait the configured duration
        yield return new WaitForSeconds(displaySeconds);

        // After the splash, force the transition to MenuPrincipal
        if (GameManager.Instance != null)
        {
            GameManager.Instance.ForceSceneChange("MenuPrincipal");
        }
        else
        {
            Debug.LogWarning("SplashController: GameManager not found. Attempting direct scene load.");
            UnityEngine.SceneManagement.SceneManager.LoadScene("MenuPrincipal");
        }
    }
}
